package com.chaobo.scm.supplier.infrastructure.persistence.profile;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.domain.profile.*;import org.springframework.stereotype.Repository;import java.util.*;
@Repository public class MyBatisSupplierAdmissionRepository implements SupplierAdmissionRepository{private final SupplierAdmissionMapper m;public MyBatisSupplierAdmissionRepository(SupplierAdmissionMapper m){this.m=m;}public Optional<SupplierAdmissionAggregate> findById(long id){var r=m.find(id);return r==null?Optional.empty():Optional.of(SupplierAdmissionAggregate.rehydrate(r.id(),r.no(),r.code(),r.name(),r.taxNo(),r.type(),r.contact(),r.mobile(),r.settlement(),r.status(),r.reject(),r.version()));}public void save(SupplierAdmissionAggregate a,long op){var r=new SupplierAdmissionMapper.Row(a.id(),a.no(),a.code(),a.name(),a.taxNo(),a.type(),a.contactName(),a.contactMobile(),a.settlementJson(),a.status().code(),a.rejectReason(),a.version());if(m.find(a.id())==null)m.insert(r,op);else if(m.update(r,a.version()-1,op)!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"准入单已更新");}}
